CREATE PROCEDURE [dbo].[SP_JOM_HUAWEI_5MIN_PULL_AND_LOAD]
(
  @Dataset     varchar(100),
  @LocalDir    varchar(400),
  @TargetTable sysname,
  @RemoteDir   varchar(400) = '/uploads/Huawei/',
  @WorkDir     varchar(200) = 'J:\Scripts',
  @WinSCP      varchar(300) = 'C:\Program Files (x86)\WinSCP\WinSCP.com',
  @OpenLine    varchar(1000) = 'open sftp://usr_clientes:usrclientes@10.226.195.34/ -hostkey="ssh-ed25519 255 cIfRfNlQVbLQfDGMARhszbB3tQ4SGlz53HVqlkLH1hE"'
  --,@CatchUpToday bit = 1
)
AS
BEGIN
  SET NOCOUNT ON;

  DECLARE @Cmd varchar(4000);

  --------------------------------------------------------------------
  -- 0) Ventana móvil: últimos 30 minutos (slots cada 5 min)
  --------------------------------------------------------------------
  DECLARE @Now datetime = GETDATE();

  -- redondeo hacia abajo a múltiplo de 5 minutos
  DECLARE @Minute int = DATEPART(MINUTE, @Now) - (DATEPART(MINUTE, @Now) % 5);
  DECLARE @SlotNow datetime = DATEADD(MINUTE, @Minute - DATEPART(MINUTE, @Now), @Now);

  -- armamos slots: -30, -25, -20, -15, -10, -5, 0
  DECLARE @Slots TABLE (TS char(12) NOT NULL PRIMARY KEY);

  DECLARE @i int = -30;
  WHILE @i <= 0
  BEGIN
    DECLARE @S datetime = DATEADD(MINUTE, @i, @SlotNow);

    INSERT INTO @Slots(TS)
    VALUES
    (
      CONVERT(char(8), @S, 112) +
      RIGHT('0' + CAST(DATEPART(HOUR, @S) AS varchar(2)), 2) +
      RIGHT('0' + CAST(DATEPART(MINUTE,@S) AS varchar(2)), 2)
    );

    SET @i += 5;
  END

  --------------------------------------------------------------------
  -- 1) Crear carpetas
  --------------------------------------------------------------------
  SET @Cmd = 'cmd /c if not exist "' + @WorkDir + '" mkdir "' + @WorkDir + '"';
  EXEC xp_cmdshell @Cmd, NO_OUTPUT;

  SET @Cmd = 'cmd /c if not exist "' + @LocalDir + '" mkdir "' + @LocalDir + '"';
  EXEC xp_cmdshell @Cmd, NO_OUTPUT;

  --------------------------------------------------------------------
  -- 2) Crear script WinSCP (descarga los últimos 30 min)
  --------------------------------------------------------------------
  DECLARE @Script varchar(300) = @WorkDir + '\get_' + @Dataset + '.txt';
  DECLARE @Log    varchar(300) = @WorkDir + '\get_' + @Dataset + '.log';

  DECLARE @WinScpLines varchar(4000) = '';

  SELECT @WinScpLines =
    @WinScpLines + ' ^& echo get "' + @Dataset + '_' + s.TS + '_*.5min.csv" "' + @LocalDir + '"'
  FROM @Slots s
  ORDER BY s.TS;

  SET @Cmd =
    'cmd /c (echo ' + @OpenLine +
    ' ^& echo cd "' + @RemoteDir + '"' +
    @WinScpLines +
    ' ^& echo exit) > "' + @Script + '"';

  EXEC xp_cmdshell @Cmd, NO_OUTPUT;

  --------------------------------------------------------------------
  -- 3) Ejecutar WinSCP
  --------------------------------------------------------------------
  SET @Cmd =
    'cmd /c ""' + @WinSCP + '" /ini=nul /log="' + @Log + '" /script="' + @Script + '""';
  EXEC xp_cmdshell @Cmd, NO_OUTPUT;

  --------------------------------------------------------------------
  -- 4) Listar archivos locales descargados dentro de ventana 30 min
  --    (NO solo el slot exacto)
  --------------------------------------------------------------------
  DECLARE @Files TABLE (Line varchar(4000));

  -- traemos todo el rango del dataset del día actual; luego filtramos por TS exactos en @Slots
  DECLARE @Today char(8) = CONVERT(char(8), @SlotNow, 112);

  SET @Cmd = 'cmd /c dir "' + @LocalDir + @Dataset + '_' + @Today + '*.5min.csv" /b';
  INSERT INTO @Files EXEC xp_cmdshell @Cmd;

  DELETE FROM @Files
   WHERE Line IS NULL
      OR Line LIKE '%File Not Found%'
      OR Line LIKE '%Not Found%'
      OR Line LIKE '%Access is denied%';

  -- quedarnos solo con los TS de la ventana
  ;WITH Parsed AS (
    SELECT
      f.Line,
      TS = SUBSTRING(f.Line, LEN(@Dataset) + 2, 12)  -- Dataset_YYYYMMDDHHMM_...
    FROM @Files f
    WHERE f.Line LIKE @Dataset + '_%.5min.csv'
  )
  DELETE f
  FROM @Files f
  WHERE NOT EXISTS (
    SELECT 1
    FROM Parsed p
    JOIN @Slots s ON s.TS = p.TS
    WHERE p.Line = f.Line
  );

  --------------------------------------------------------------------
  -- 5) Cargar los que NO estén ya cargados (control)
  --------------------------------------------------------------------
  DECLARE @File varchar(260);

  DECLARE cur CURSOR LOCAL FAST_FORWARD FOR
    SELECT Line
    FROM @Files f
    WHERE NOT EXISTS (
      SELECT 1
      FROM Repo_origen_matrix.dbo.CTL_5MIN_FILES c
      WHERE c.Dataset = @Dataset AND c.FileName = f.Line AND c.Status = 'LOADED'
    );

  OPEN cur;
  FETCH NEXT FROM cur INTO @File;

  WHILE @@FETCH_STATUS = 0
  BEGIN
    ----------------------------------------------------------------
    -- 5.1) DISCRIMINAR ARCHIVO VACÍO (0 bytes)
    ----------------------------------------------------------------
    DECLARE @FileSize bigint = NULL;

    DECLARE @SizeCmd varchar(4000) =
      'cmd /c for %A in ("' + @LocalDir + @File + '") do @echo %~zA';

    DECLARE @SizeOut TABLE (Line varchar(100));
    DELETE FROM @SizeOut;

    INSERT INTO @SizeOut
    EXEC xp_cmdshell @SizeCmd;

    SELECT TOP 1 @FileSize = TRY_CAST(Line AS bigint)
    FROM @SizeOut
    WHERE Line IS NOT NULL;

    IF ISNULL(@FileSize,0) = 0
    BEGIN
      MERGE Repo_origen_matrix.dbo.CTL_5MIN_FILES AS t
      USING (SELECT @Dataset AS Dataset, @File AS FileName) s
      ON (t.Dataset=s.Dataset AND t.FileName=s.FileName)
      WHEN MATCHED THEN
        UPDATE SET Status='EMPTY', ErrorMessage='0 bytes', LoadedAt=SYSDATETIME()
      WHEN NOT MATCHED THEN
        INSERT (Dataset, FileName, Status, ErrorMessage)
        VALUES (s.Dataset, s.FileName, 'EMPTY', '0 bytes');

      SET @Cmd = 'cmd /c del "' + @LocalDir + @File + '"';
      EXEC xp_cmdshell @Cmd, NO_OUTPUT;

      FETCH NEXT FROM cur INTO @File;
      CONTINUE;
    END

    ----------------------------------------------------------------
    -- 5.2) DISCRIMINAR ARCHIVO SOLO HEADER (sin data)
    ----------------------------------------------------------------
    DECLARE @LineCount int = NULL;

    DECLARE @CountCmd varchar(4000) =
      'cmd /c find /v /c "" "' + @LocalDir + @File + '"';

    DECLARE @CountOut TABLE (Line varchar(200));
    DELETE FROM @CountOut;

    INSERT INTO @CountOut
    EXEC xp_cmdshell @CountCmd;

    SELECT TOP 1 @LineCount =
      TRY_CAST(RIGHT(Line, CHARINDEX(':', REVERSE(Line)) - 1) AS int)
    FROM @CountOut
    WHERE Line LIKE '%:%';

    IF ISNULL(@LineCount,0) <= 1
    BEGIN
      MERGE Repo_origen_matrix.dbo.CTL_5MIN_FILES AS t
      USING (SELECT @Dataset AS Dataset, @File AS FileName) s
      ON (t.Dataset=s.Dataset AND t.FileName=s.FileName)
      WHEN MATCHED THEN
        UPDATE SET Status='EMPTY', ErrorMessage='Only header / no data', LoadedAt=SYSDATETIME()
      WHEN NOT MATCHED THEN
        INSERT (Dataset, FileName, Status, ErrorMessage)
        VALUES (s.Dataset, s.FileName, 'EMPTY', 'Only header / no data');

      SET @Cmd = 'cmd /c del "' + @LocalDir + @File + '"';
      EXEC xp_cmdshell @Cmd, NO_OUTPUT;

      FETCH NEXT FROM cur INTO @File;
      CONTINUE;
    END

    ----------------------------------------------------------------
    -- 5.3) CARGA NORMAL
    ----------------------------------------------------------------
    BEGIN TRY
      DECLARE @SQL nvarchar(max) =
        N'BULK INSERT ' + QUOTENAME(PARSENAME(@TargetTable,3)) + N'.' + QUOTENAME(PARSENAME(@TargetTable,2)) + N'.' + QUOTENAME(PARSENAME(@TargetTable,1)) + N'
          FROM ' + QUOTENAME(@LocalDir + @File,'''') + N'
          WITH (
            FIRSTROW = 2,
            FIELDTERMINATOR = '','',
            ROWTERMINATOR = ''0x0d0a'',
            CODEPAGE = ''65001'',
            TABLOCK
          );';

      EXEC sp_executesql @SQL;

      MERGE Repo_origen_matrix.dbo.CTL_5MIN_FILES AS t
      USING (SELECT @Dataset AS Dataset, @File AS FileName) s
      ON (t.Dataset=s.Dataset AND t.FileName=s.FileName)
      WHEN MATCHED THEN
        UPDATE SET Status='LOADED', ErrorMessage=NULL, LoadedAt=SYSDATETIME()
      WHEN NOT MATCHED THEN
        INSERT (Dataset, FileName, Status) VALUES (s.Dataset, s.FileName, 'LOADED');

      SET @Cmd = 'cmd /c del "' + @LocalDir + @File + '"';
      EXEC xp_cmdshell @Cmd, NO_OUTPUT;

    END TRY
    BEGIN CATCH
      DECLARE @Err varchar(4000) = ERROR_MESSAGE();

      MERGE Repo_origen_matrix.dbo.CTL_5MIN_FILES AS t
      USING (SELECT @Dataset AS Dataset, @File AS FileName) s
      ON (t.Dataset=s.Dataset AND t.FileName=s.FileName)
      WHEN MATCHED THEN
        UPDATE SET Status='FAILED', ErrorMessage=@Err, LoadedAt=SYSDATETIME()
      WHEN NOT MATCHED THEN
        INSERT (Dataset, FileName, Status, ErrorMessage)
        VALUES (s.Dataset, s.FileName, 'FAILED', @Err);
    END CATCH;

    FETCH NEXT FROM cur INTO @File;
  END

  CLOSE cur;
  DEALLOCATE cur;

  --------------------------------------------------------------------
  -- 6) LIMPIEZA FINAL: eliminar script y log generados
  --------------------------------------------------------------------

  -- Eliminar archivo script WinSCP (.txt)
  IF @Script IS NOT NULL
  BEGIN
      SET @Cmd = 'cmd /c if exist "' + @Script + '" del /q "' + @Script + '"';
      EXEC xp_cmdshell @Cmd, NO_OUTPUT;
  END

  -- Eliminar archivo log WinSCP (.log)
  IF @Log IS NOT NULL
  BEGIN
      SET @Cmd = 'cmd /c if exist "' + @Log + '" del /q "' + @Log + '"';
      EXEC xp_cmdshell @Cmd, NO_OUTPUT;
  END

END

CREATE PROCEDURE dbo.SP_JOM_HUAWEI_5MIN_PULL_AND_LOAD_DIA
(
  @Dataset     varchar(100),   -- ej: 't_oifde_ivr_simple_journey'
  @LocalDir    varchar(400),   -- ej: 'J:\Huawei\5min\t_oifde_ivr_simple_journey\'
  @TargetTable sysname,        -- ej: 'Repo_origen_matrix.dbo.t_oifde_ivr_simple_journey_202602_TODAY'

  @LoadDate    date = NULL,    -- <-- NUEVO: si lo mandas, carga TODO ese día (yyyymmdd)

  @RemoteDir   varchar(400) = '/uploads/Huawei/',  -- remoto
  @WorkDir     varchar(200) = 'C:\Scripts',
  @WinSCP      varchar(300) = 'C:\Program Files (x86)\WinSCP\WinSCP.com',
  @OpenLine    varchar(1000) = 'open sftp://usr_clientes:usrclientes@10.226.195.34/ -hostkey="ssh-ed25519 255 cIfRfNlQVbLQfDGMARhszbB3tQ4SGlz53HVqlkLH1hE"'
)
AS
BEGIN
  SET NOCOUNT ON;

  DECLARE @Cmd varchar(4000);

  --------------------------------------------------------------------
  -- 0) Definir máscara remota/local
  --    - Si @LoadDate IS NULL => slot actual (yyyymmddHHmm)
  --    - Si @LoadDate NOT NULL => día completo (yyyymmdd)
  --------------------------------------------------------------------
  DECLARE @TS char(12) = NULL;
  DECLARE @D  char(8);

  IF @LoadDate IS NULL
  BEGIN
    DECLARE @Now datetime = GETDATE();

    -- redondeo hacia abajo a múltiplo de 5 minutos
    DECLARE @Minute int = DATEPART(MINUTE, @Now) - (DATEPART(MINUTE, @Now) % 5);
    DECLARE @Slot datetime = DATEADD(MINUTE, @Minute - DATEPART(MINUTE, @Now), @Now);

    SET @TS =
      CONVERT(char(8), @Slot, 112) +
      RIGHT('0' + CAST(DATEPART(HOUR, @Slot) AS varchar(2)), 2) +
      RIGHT('0' + CAST(DATEPART(MINUTE,@Slot) AS varchar(2)), 2);

    SET @D = LEFT(@TS, 8);
  END
  ELSE
  BEGIN
    SET @D = CONVERT(char(8), @LoadDate, 112); -- yyyymmdd
  END

  DECLARE @RemoteMask varchar(300) =
    CASE
      WHEN @LoadDate IS NULL
        THEN @Dataset + '_' + @TS + '_*.5min.csv'
      ELSE
        @Dataset + '_' + @D + '*.5min.csv'    -- día completo (captura yyyymmddHHmm_*)
    END;

  --------------------------------------------------------------------
  -- 1) Crear carpetas
  --------------------------------------------------------------------
  SET @Cmd = 'cmd /c if not exist "' + @WorkDir + '" mkdir "' + @WorkDir + '"';
  EXEC xp_cmdshell @Cmd, NO_OUTPUT;

  SET @Cmd = 'cmd /c if not exist "' + @LocalDir + '" mkdir "' + @LocalDir + '"';
  EXEC xp_cmdshell @Cmd, NO_OUTPUT;

  --------------------------------------------------------------------
  -- 2) Crear script WinSCP (único por dataset, lo sobrescribe)
  --------------------------------------------------------------------
  DECLARE @Script varchar(300) = @WorkDir + '\get_' + @Dataset + '.txt';
  DECLARE @Log    varchar(300) = @WorkDir + '\get_' + @Dataset + '.log';

  SET @Cmd =
    'cmd /c (echo ' + @OpenLine +
    ' ^& echo cd "' + @RemoteDir + '"' +
    ' ^& echo get "' + @RemoteMask + '" "' + @LocalDir + '"' +
    ' ^& echo exit) > "' + @Script + '"';

  EXEC xp_cmdshell @Cmd, NO_OUTPUT;

  --------------------------------------------------------------------
  -- 3) Ejecutar WinSCP
  --------------------------------------------------------------------
  SET @Cmd =
    'cmd /c ""' + @WinSCP + '" /ini=nul /log="' + @Log + '" /script="' + @Script + '""';
  EXEC xp_cmdshell @Cmd, NO_OUTPUT;

  --------------------------------------------------------------------
  -- 4) Listar archivos descargados (slot o día, según corresponda)
  --------------------------------------------------------------------
  DECLARE @Files TABLE (Line varchar(4000));

  IF @LoadDate IS NULL
    SET @Cmd = 'cmd /c dir "' + @LocalDir + @Dataset + '_' + @TS + '_*.5min.csv" /b';
  ELSE
    SET @Cmd = 'cmd /c dir "' + @LocalDir + @Dataset + '_' + @D  + '*.5min.csv" /b';

  INSERT INTO @Files EXEC xp_cmdshell @Cmd;

  DELETE FROM @Files
   WHERE Line IS NULL
      OR Line LIKE '%File Not Found%'
      OR Line LIKE '%Not Found%'
      OR Line LIKE '%Access is denied%';

  --------------------------------------------------------------------
  -- 5) Cargar los que NO estén ya cargados (control)
  --------------------------------------------------------------------
  DECLARE @File varchar(260);

  DECLARE cur CURSOR LOCAL FAST_FORWARD FOR
    SELECT Line
    FROM @Files f
    WHERE NOT EXISTS (
      SELECT 1
      FROM Repo_origen_matrix.dbo.CTL_5MIN_FILES c
      WHERE c.Dataset = @Dataset AND c.FileName = f.Line AND c.Status = 'LOADED'
    );

  OPEN cur;
  FETCH NEXT FROM cur INTO @File;

  WHILE @@FETCH_STATUS = 0
  BEGIN
    BEGIN TRY
      DECLARE @SQL nvarchar(max) =
        N'BULK INSERT ' + QUOTENAME(PARSENAME(@TargetTable,3)) + N'.' + QUOTENAME(PARSENAME(@TargetTable,2)) + N'.' + QUOTENAME(PARSENAME(@TargetTable,1)) + N'
          FROM ' + QUOTENAME(@LocalDir + @File,'''') + N'
          WITH (
            FIRSTROW = 2,
            FIELDTERMINATOR = '','',
            ROWTERMINATOR = ''0x0d0a'',
            CODEPAGE = ''65001'',
            TABLOCK
          );';

      EXEC sp_executesql @SQL;

      MERGE Repo_origen_matrix.dbo.CTL_5MIN_FILES AS t
      USING (SELECT @Dataset AS Dataset, @File AS FileName) s
      ON (t.Dataset=s.Dataset AND t.FileName=s.FileName)
      WHEN MATCHED THEN
        UPDATE SET Status='LOADED', ErrorMessage=NULL, LoadedAt=SYSDATETIME()
      WHEN NOT MATCHED THEN
        INSERT (Dataset, FileName, Status) VALUES (s.Dataset, s.FileName, 'LOADED');

      -- borrar archivo local SOLO si cargó OK
      SET @Cmd = 'cmd /c del "' + @LocalDir + @File + '"';
      EXEC xp_cmdshell @Cmd, NO_OUTPUT;

    END TRY
    BEGIN CATCH
      DECLARE @Err varchar(4000) = ERROR_MESSAGE();

      MERGE Repo_origen_matrix.dbo.CTL_5MIN_FILES AS t
      USING (SELECT @Dataset AS Dataset, @File AS FileName) s
      ON (t.Dataset=s.Dataset AND t.FileName=s.FileName)
      WHEN MATCHED THEN
        UPDATE SET Status='FAILED', ErrorMessage=@Err, LoadedAt=SYSDATETIME()
      WHEN NOT MATCHED THEN
        INSERT (Dataset, FileName, Status, ErrorMessage) VALUES (s.Dataset, s.FileName, 'FAILED', @Err);

      -- NO borres el archivo si falló
    END CATCH;

    FETCH NEXT FROM cur INTO @File;
  END

  CLOSE cur;
  DEALLOCATE cur;
END

