CREATE PROCEDURE [dbo].[SP_Actualizar_Bajas_Retenciones_movil]
    @PeriodoBase VARCHAR(6) = NULL
AS
BEGIN
    SET NOCOUNT ON;

    IF @PeriodoBase IS NULL
    BEGIN
        SELECT @PeriodoBase = MAX(Periodo)
        FROM Repo_Retenciones.dbo.JOM_SEGUIMIENTO_BAJAS_RETENCIONES;
    END;

    DECLARE @PeriodoM1 VARCHAR(6);
    DECLARE @PeriodoM2 VARCHAR(6);
    DECLARE @PeriodoM3 VARCHAR(6);
    DECLARE @SQL NVARCHAR(MAX);
    DECLARE @TablaM1 NVARCHAR(50);
    DECLARE @TablaM2 NVARCHAR(50);

    -- Calcular periodos
    SET @PeriodoM1 = CONVERT(CHAR(6), DATEADD(MONTH, -1, CONVERT(DATE, @PeriodoBase + '01')), 112);
    SET @PeriodoM2 = CONVERT(CHAR(6), DATEADD(MONTH, -2, CONVERT(DATE, @PeriodoBase + '01')), 112);
    SET @PeriodoM3 = CONVERT(CHAR(6), DATEADD(MONTH, -3, CONVERT(DATE, @PeriodoBase + '01')), 112);

    -- 🔎 Buscar el M-1 más reciente disponible
    IF OBJECT_ID('Repo_Planta.dbo.PLANTA_MOVIL_' + @PeriodoM1) IS NOT NULL
        SET @TablaM1 = 'Repo_Planta.dbo.PLANTA_MOVIL_' + @PeriodoM1;
    ELSE IF OBJECT_ID('Repo_Planta.dbo.PLANTA_MOVIL_' + @PeriodoM2) IS NOT NULL
        SET @TablaM1 = 'Repo_Planta.dbo.PLANTA_MOVIL_' + @PeriodoM2;
    ELSE IF OBJECT_ID('Repo_Planta.dbo.PLANTA_MOVIL_' + @PeriodoM3) IS NOT NULL
        SET @TablaM1 = 'Repo_Planta.dbo.PLANTA_MOVIL_' + @PeriodoM3;
    ELSE
        SET @TablaM1 = NULL;

    -- 🔎 Buscar el siguiente disponible para M-2
    IF OBJECT_ID('Repo_Planta.dbo.PLANTA_MOVIL_' + @PeriodoM2) IS NOT NULL
        SET @TablaM2 = 'Repo_Planta.dbo.PLANTA_MOVIL_' + @PeriodoM2;
    ELSE IF OBJECT_ID('Repo_Planta.dbo.PLANTA_MOVIL_' + @PeriodoM3) IS NOT NULL
        SET @TablaM2 = 'Repo_Planta.dbo.PLANTA_MOVIL_' + @PeriodoM3;
    ELSE
        SET @TablaM2 = NULL;

    -- Limpiar datos previos
    DELETE FROM Repo_Retenciones.dbo.JOM_SEGUIMIENTO_BAJAS_RETENCIONES_MOVIL
    WHERE Periodo = @PeriodoBase;

    -- Construcción dinámica
    SET @SQL = '
    WITH SolicitudesUnicas AS (
        SELECT 
            TELEFONO_GESTION,
            FECHA_REGISTRO,
            canal_inicial,
            SOLICITUD_2,
            ROW_NUMBER() OVER (
                PARTITION BY TELEFONO_GESTION 
                ORDER BY FECHA_REGISTRO DESC
            ) AS rn
        FROM Repo_Retenciones.dbo.RETENCIONES_MOVIL_MKT
        WHERE SOLICITUD_2 = ''Baja Postpago''
    )
    INSERT INTO Repo_Retenciones.dbo.JOM_SEGUIMIENTO_BAJAS_RETENCIONES_MOVIL
    SELECT 
        A.Anexo,
        A.Fecha,
        A.Periodo,
        A.ORDER_ITEM_TYPE_DESC,
        A.ORDER_ACTION_REASON_DESC,
        A.ORDER_CREATOR,
        A.canal,
        A.nomb_canal,
        A.nomb_entidad_venta,
        A.nomb_punto_venta,
        A.Gestion,
        CASE WHEN s.canal_inicial IS NOT NULL THEN 1 ELSE 0 END AS flag_sol_mes,
        CASE WHEN COALESCE(b.MesID, c.MesID) IS NOT NULL THEN 1 ELSE 0 END AS flag_planta,
        COALESCE(b.MesID, c.MesID) AS periodo_planta,
        COALESCE(b.NumeroTelefono, c.NumeroTelefono) AS telefono,
        COALESCE(b.FechaInicioVigencia, c.FechaInicioVigencia) AS fecha_alta,
        COALESCE(b.TipoIdentificacionPersonaCD, c.TipoIdentificacionPersonaCD) AS tipo_dni,
        COALESCE(b.NumeroIdentificacionPersona, c.NumeroIdentificacionPersona) AS nro_doc,
        COALESCE(b.RENTA, c.RENTA) AS cf_plan,
        s.FECHA_REGISTRO AS fecha_solicitud,
        s.canal_inicial
    FROM Repo_Retenciones.dbo.JOM_SEGUIMIENTO_BAJAS_RETENCIONES A
    ';

    IF @TablaM1 IS NOT NULL
        SET @SQL += ' LEFT JOIN ' + @TablaM1 + ' b ON a.Anexo = RIGHT(b.SuscripcionCD,9)';
    IF @TablaM2 IS NOT NULL
        SET @SQL += ' LEFT JOIN ' + @TablaM2 + ' c ON a.Anexo = RIGHT(c.SuscripcionCD,9)';

    SET @SQL += '
    LEFT JOIN SolicitudesUnicas s
        ON s.TELEFONO_GESTION = COALESCE(b.NumeroTelefono, c.NumeroTelefono)
       AND s.rn = 1
       AND s.FECHA_REGISTRO >= DATEADD(MONTH, -1, CAST(A.Fecha AS date))
       AND s.FECHA_REGISTRO <  DATEADD(MONTH,  1, CAST(A.Fecha AS date))
    WHERE A.Periodo = ''' + @PeriodoBase + ''';';

    EXEC sp_executesql @SQL;
END;

CREATE PROCEDURE dbo.sp_alterdiagram
(
	@diagramname 	sysname,
	@owner_id	int	= null,
	@version 	int,
	@definition 	varbinary(max)
)
WITH EXECUTE AS 'dbo'
AS
BEGIN
	set nocount on

	declare @theId 			int
	declare @retval 		int
	declare @IsDbo 			int

	declare @UIDFound 		int
	declare @DiagId			int
	declare @ShouldChangeUID	int

	if(@diagramname is null)
	begin
		RAISERROR ('Invalid ARG', 16, 1)
		return -1
	end

	execute as caller;
	select @theId = DATABASE_PRINCIPAL_ID();	 
	select @IsDbo = IS_MEMBER(N'db_owner'); 
	if(@owner_id is null)
		select @owner_id = @theId;
	revert;

	select @ShouldChangeUID = 0
	select @DiagId = diagram_id, @UIDFound = principal_id from dbo.sysdiagrams where principal_id = @owner_id and name = @diagramname 

	if(@DiagId IS NULL or (@IsDbo = 0 and @theId <> @UIDFound))
	begin
		RAISERROR ('Diagram does not exist or you do not have permission.', 16, 1);
		return -3
	end

	if(@IsDbo <> 0)
	begin
		if(@UIDFound is null or USER_NAME(@UIDFound) is null) -- invalid principal_id
		begin
			select @ShouldChangeUID = 1 ;
		end
	end

	-- update dds data			
	update dbo.sysdiagrams set definition = @definition where diagram_id = @DiagId ;

	-- change owner
	if(@ShouldChangeUID = 1)
		update dbo.sysdiagrams set principal_id = @theId where diagram_id = @DiagId ;

	-- update dds version
	if(@version is not null)
		update dbo.sysdiagrams set version = @version where diagram_id = @DiagId ;

	return 0
END

CREATE PROCEDURE [internal].[append_event_message]
        @operation_id       bigint,                             
        @message_type       int,                                
        @message_time         datetimeoffset,                     
        @message_source       smallint,                           
        @message              nvarchar(max),                      
        @extended_info_id     bigint = NULL,
        @package_name         nvarchar(260),
        @package_location_type nvarchar(128),
	@package_path_full    nvarchar(4000),
        @event_name           nvarchar(1024),
        @message_source_name  nvarchar(4000),
        @message_source_id    nvarchar(38),
        @subcomponent_name    nvarchar(4000),
        @package_path         nvarchar(MAX),
        @execution_path       nvarchar(MAX),
        @thread_id            int,
        @message_code         int,
        @event_message_id     bigint output
AS
SET NOCOUNT ON

    DECLARE @operation_message_id   bigint    

    IF [internal].[check_permission] 
    (
        4,
        @operation_id,
        2
    ) = 0
    BEGIN
        RAISERROR(27143, 16, 5, @operation_id) WITH NOWAIT;
        RETURN 1;      
    END

    INSERT INTO [internal].[operation_messages] 
           ([operation_id], 
            [message_type], 
            [message_time],
            [message_source_type], 
            [message], 
            [extended_info_id])
        VALUES(
            @operation_id,  
            @message_type,
            @message_time,
            @message_source,
            @message,
            @extended_info_id)

    SET @operation_message_id = SCOPE_IDENTITY()

    INSERT INTO [internal].[event_messages]
           ([operation_id],
           [event_message_id],
           [package_name],
	   [package_location_type],
	   [package_path_full],
           [event_name],
           [message_source_name],
           [message_source_id],
           [subcomponent_name],
           [package_path],
           [execution_path],
           [threadID],
           [message_code])
     VALUES
           (
           @operation_id,
           @operation_message_id,
           @package_name,
           @package_location_type,
           @package_path_full,
           @event_name,
           @message_source_name,
           @message_source_id,
           @subcomponent_name,
           @package_path,
           @execution_path,
           @thread_id,
           @message_code
           )
    SET @event_message_id =  @operation_message_id
    RETURN 0

CREATE PROCEDURE [internal].[append_executable_statistics]
        @operation_id       bigint,                             
        @project_id         bigint,
        @version_id         bigint,
        @package_name       nvarchar(260),
        @package_location_type nvarchar(128),
	@package_path_full    nvarchar(4000),
        @executable_name    nvarchar(4000),
        @executable_guid    nvarchar(38),
        @package_path       nvarchar(MAX),
        @execution_path     nvarchar(MAX),
        @start_time         datetimeoffset(7),
        @end_time           datetimeoffset(7),
        @execution_hierarchy hierarchyid = null,
        @execution_duration  int,
        @execution_result    smallint,
        @execution_value     sql_variant
AS
SET NOCOUNT ON

    DECLARE @executable_id bigint


    IF [internal].[check_permission] 
    (
        4,
        @operation_id,
        2
    ) = 0
    BEGIN
        RAISERROR(27143, 16, 5, @operation_id) WITH NOWAIT;
        RETURN 1;      
    END


    SELECT @executable_id = [executable_id] FROM internal.executables
        WHERE project_id = @project_id AND project_version_lsn = @version_id
        AND package_name = @package_name AND executable_name = @executable_name
        AND executable_guid = @executable_guid AND package_path = @package_path

    IF @executable_id IS NULL
    BEGIN

        INSERT INTO [internal].[executables]
           ([project_id],
           [project_version_lsn],
           [package_name],
	   [package_location_type],
	   [package_path_full],
           [executable_name],
           [executable_guid],
           [package_path])
        VALUES
           (
             @project_id,
             @version_id,
             @package_name,
             @package_location_type,
	     @package_path_full,
             @executable_name,
             @executable_guid,
             @package_path
           )
        SET @executable_id = SCOPE_IDENTITY()      
    END 

    INSERT INTO [internal].[executable_statistics]
           ([execution_id],
           [executable_id],
           [execution_path],
           [start_time],
           [end_time],
           [execution_hierarchy],
           [execution_duration],
           [execution_result],
           [execution_value])
     VALUES
           (
               @operation_id,
               @executable_id,
               @execution_path,
               @start_time,
               @end_time,
               null,
               @execution_duration,
               @execution_result,
               @execution_value
           )

    RETURN 0

CREATE PROCEDURE [internal].[append_execution_component_phases]
        @execution_id                 bigint,                             
        @package_name                 nvarchar(260),
        @package_location_type        nvarchar(128),
        @package_path_full            nvarchar(4000),                            
        @task_name                    nvarchar(4000),                                
        @subcomponent_name            nvarchar(4000),
        @phase                        sysname,
        @is_start                     bit,
        @start_phase_time             datetimeoffset,
        @end_phase_time               datetimeoffset,
        @execution_path               nvarchar(MAX),
        @sequence_id                  int
AS
SET NOCOUNT ON

    IF [internal].[check_permission] 
    (
        4,
        @execution_id,
        2
    ) = 0
    BEGIN
        RAISERROR(27143, 16, 5, @execution_id) WITH NOWAIT;
        RETURN 1;      
    END

    DECLARE @phase_time datetimeoffset
    SET @phase_time = NULL;

    IF(@is_start = 'False')
    BEGIN
        UPDATE [internal].[execution_component_phases] 
        SET [phase_time] = @start_phase_time
        WHERE [sequence_id] = @sequence_id 
        AND [execution_id] = @execution_id;

        SET @phase_time = @end_phase_time;
    END

    INSERT INTO [internal].[execution_component_phases]
           ([execution_id],
            [package_name],
            [package_location_type],
            [package_path_full],
